head.script:
//전역변수
scwin.userInfo = "";

//-------------------------------------------------------------------------
// TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    //로그인정보 추출
    scwin.userInfo = $c.data.getMemInfo();

    const codeOptions = [
        { grpCd: "ZZ210", compID: "lc_cartypeCd" } // 장비구분
    ];
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
    var e = await $c.sbm.execute(sbm_combo1);

    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        lc_homeClsCd.setSelectedIndex(0);
        lc_homeClsCd.setValue(scwin.userInfo.eqHomeClsCd); // 정비소속구분코드
        await scwin.lc_homeClsCd_onviewchange();

        //tobe 추가
        // var startDt = $c.date.getServerDateTime("yyyy") + "0101";
        // var endDt = $c.date.getServerDateTime("yyyyMM") + "01";
        var startDt = $c.date.getServerDateTime("yyyyMM");
        var endDt = $c.date.getServerDateTime("yyyyMM");
        ed_wrkStDt.setValue(startDt);
        ed_wrkEndDt.setValue(endDt);

        ed_wrkStDt.focus();
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    if (!await $c.gus.cfValidate([tb_wrk])) return;

    if (ed_wrkStDt.getValue() > ed_wrkEndDt.getValue()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_wrkStDt.focus();
        return;
    }

    //ds_fix_work_re.UseChangeInfo = false; // 조회조건

    dma_fix_work_re.set("termFrom", ed_wrkStDt.getValue());
    dma_fix_work_re.set("termTo", ed_wrkEndDt.getValue());
    dma_fix_work_re.set("repFixWrkPlCd", lc_repWrkPlCd.getValue());
    dma_fix_work_re.set("fixWrkPlCd", lc_wrkPlCd.getValue());
    dma_fix_work_re.set("cartypeCd", lc_cartypeCd.getValue());
    dma_fix_work_re.set("acctDeptCd", ed_acctDeptCd.getValue());
    dma_fix_work_re.set("eqCd", ed_eqCd.getValue());
    dma_fix_work_re.set("acctGb", lc_acctGb.getValue());

    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        var rowCnt = ds_fix_work_list.getRowCount();

        // ds_crosstab 초기화
        ds_crosstab.removeAll();

        for (var i = 1; i < 200; i++) {
            gr_work_pl.setColumnVisible(`bilgAmt${i}`, false);
        }

        if (rowCnt == 0) {
            await $c.win.alert("조회된 데이터가 없습니다.");
            return;
        }

        //ds_crosstab 생성
        var originJson = ds_fix_work_list.getAllJSON();
        var colData = [];
        var allJson = [];
        var crossRJson = {};
        var crossRow = -1;
        var sumRow = [];
        var sum = 0;

        originJson.forEach(function (rowJson, index) {
            //컬럼 생성
            if (!colData.includes(rowJson.wrkEndDt)) {
                colData.push(rowJson.wrkEndDt);
            }

            if (colData.length > 200) return;


            var rowKey = `${rowJson.vehclNo}_${rowJson.vehclNoAcctDeptNm}_${rowJson.outAcctNm}`;

            if (!crossRJson[rowKey]) {
                crossRJson[rowKey] = rowJson;
                crossRow = 1 + crossRow; //ds_crosstab row 수 측정
                sum = 0; //각 row마다 합계 측정
            }

            var dateIdx = colData.indexOf(rowJson.wrkEndDt);

            if (dateIdx > -1) {
                crossRJson[rowKey]["bilgAmt" + dateIdx] = rowJson.bilgAmt
                sum = sum + $c.num.parseInt(rowJson.bilgAmt)
                crossRJson[rowKey]["Sum"] = sum
            }

            if (crossRJson[rowKey]["vehclNo"] == "합계") {
                sumRow.push(crossRow);
            }
        });

        for (key in crossRJson) {
            allJson.push(crossRJson[key]);
        }

        ds_crosstab.setJSON(allJson);

        //컬럼 show, 헤더값 셋팅
        for (var i = 0; i < colData.length; i++) {
            gr_work_pl.setColumnVisible(`bilgAmt${i}`, true);
            gr_work_pl.setHeaderValue(`wrkEndDt${i}`, colData[i]);
        }

        //sort
        var options = {};
        options.sortIndex = "vehclNoAcctDeptNm acctDeptNmtm outAcctCd wrkEndDt";
        options.sortOrder = "1 1 1 1";

        ds_crosstab.multisort(options);

        //마지막 합계부분 색깔 변경
        for (var i = 0; i < sumRow.length; i++) {
            gr_work_pl.setRowBackgroundColor(sumRow[i], "#FFD9C2");
        }

        totalRows.setValue(ds_crosstab.getRowCount());
    };
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    var pWhere = "";
    switch (disGubun) {
        case 1:
            // 장비 팝업			
            await udc_eqCd.cfCommonPopUp(scwin.udc_eqCd_callbackFunc // XML상의 SELECT ID	
                , ed_eqCd.getValue().trim()      // 화면에서의 Code Element의	Value
                , ed_vehclNo.getValue()		  // 화면에서의 Name Element의	Value
                , pClose					  // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					  // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					  // Title순서	
                , null					  // 보여주는 각 컬럼들의 폭	
                , null					  // 컬럼중에서 숨기는	컬럼 지정	
                , lc_homeClsCd.getValue()  // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					  // POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					  // POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					  // 윈도우 위치 Y좌표	
                , null					  // 윈도우 위치 X좌표
                , null					  // 중복체크여부	("F")
                , "F"					  // 전체검색허용여부	("F")
                , "장비,장비코드,차량번호"	  // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
            );

            break;

        case 2:
            // 귀속부서 팝업			
            await udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callbackFunc 	// XML상의 SELECT ID	
                , ed_acctDeptCd.getValue().trim()      // 화면에서의 Code Element의	Value
                , ed_acctDeptNm.getValue() 		    // 화면에서의 Name Element의	Value
                , pClose					  // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)                                    
                , null					  // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					  // Title순서	
                , null					  // 보여주는 각 컬럼들의 폭	
                , null					  // 컬럼중에서 숨기는	컬럼 지정	
                , pWhere					  // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					  // POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					  // POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					  // 윈도우 위치 Y좌표	
                , null					  // 윈도우 위치 X좌표
                , null					  // 중복체크여부	("F")
                , "T"				  // 전체검색허용여부	("F")
                , "귀속부서,부서코드,부서명"	  // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
            );

            break;
    }
};

//-------------------------------------------------------------------------
//팝업콜백
//-------------------------------------------------------------------------
//장비
scwin.udc_eqCd_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_eqCd, ed_vehclNo);
};

//귀속부서
scwin.udc_acctDeptCd_callbackFunc = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_acctDeptCd, ed_acctDeptNm);
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if ($c.gus.cfIsNull(isCode) || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

//-------------------------------------------------------------------------
// 조회 조건 지우기
//-------------------------------------------------------------------------
scwin.f_FieldClear = async function (e) {
    $c.gus.cfInitObjects(tb_wrk, null);
    lc_homeClsCd.setValue(scwin.userInfo.eqHomeClsCd); // 정비소속구분코드
    await scwin.lc_homeClsCd_onviewchange();
    if (lc_homeClsCd.getValue() == scwin.userInfo.eqHomeClsCd) {
        lc_repWrkPlCd.setValue(scwin.userInfo.fixWrkPlCd); // 정비작업장코드
    }
};

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = function () {
    var infoArr = [];

    var hiddenCnt = 0;
    gr_work_pl.hiddenList.sort(function (t) { if (t == true) hiddenCnt++; });
    var colSpan = gr_work_pl.getColCnt() - hiddenCnt;

    infoArr = [{
        rowIndex: 0,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: "차량별 계정별 누계 조회",
        textAlign: "center",
        fontSize: 12,
        drawBorder: false
    }, {
        rowIndex: 2,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `정비기간 [${$c.date.formatDateTime(ed_wrkStDt.getValue(), "yyyy/MM")}/ ~ ${$c.date.formatDateTime(ed_wrkEndDt.getValue(), "yyyy/MM")}/]`,
        textAlign: "left",
        fontSize: 12,
        drawBorder: false
    }, {
        rowIndex: 3,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `사업부문 [${lc_homeClsCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 12,
        drawBorder: false
    }, {
        rowIndex: 4,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `대표정비작업장 [${lc_repWrkPlCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 12,
        drawBorder: false
    }, {
        rowIndex: 5,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `정비작업장 [${lc_wrkPlCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 12,
        drawBorder: false
    }, {
        rowIndex: 6,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `장비구분 [${lc_cartypeCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 12,
        drawBorder: false
    }, {
        rowIndex: 7,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `구분 [${lc_acctGb.getText(true)}]`,
        textAlign: "left",
        fontSize: 12,
        drawBorder: false
    }];

    var infoAddArr = {};
    var indx = 8;
    if (ed_eqCd.getValue().trim() != "") {
        infoAddArr = {
            rowIndex: indx,
            colIndex: 0,
            rowSpan: 1,
            colSpan: colSpan,
            text: `장비 [${ed_eqCd.getValue()}-${ed_vehclNo.getValue()}]`,
            textAlign: "left",
            fontSize: 12,
            drawBorder: false
        };

        infoArr.push(infoAddArr);

        indx = indx + 1;
    }

    if (ed_acctDeptCd.getValue().trim() != "") {
        infoAddArr = {
            rowIndex: indx,
            colIndex: 0,
            rowSpan: 1,
            colSpan: colSpan,
            text: `귀속부서 [${ed_acctDeptCd.getValue()}-${ed_acctDeptNm.getValue()}]`,
            textAlign: "left",
            fontSize: 12,
            drawBorder: false
        };

        infoArr.push(infoAddArr);
        indx = indx + 1;
    }

    var options = {
        fileName: "차량별 계정별 누계 조회.xlsx",
        sheetName: "차량별 계정별 누계 조회",
        useSubTotal: "true",
        useSubTotalData: "true",
        startRowIndex: indx,
        startColumnIndex: 0,
        type: 1,
        columnMove: true, //그리드 컬럼이동시 이동된 상태로 다운로드 유무 ( "true"인경우 컬럼이동 순서대로 출력 )
        colMerge: true,  //colMerge된 컬럼을 Merge해서 출력 할 지 여부
        colMergeTextAlign: "top",//colMerge된 컬럼의 textAlign설정 (bottom, center, top 설정)
    };

    $c.data.downloadGridViewExcel(gr_work_pl, options, infoArr);
};

//-------------------------------------------------------------------------
// 대표정비작업장콤보 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveSecond = function (param1) {
    dma_combo.set("strVal", param1);

    $c.sbm.execute(sbm_combo);
};

scwin.sbm_combo_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        lc_repWrkPlCd.setSelectedIndex(0);

        if (lc_homeClsCd.getValue() == scwin.userInfo.eqHomeClsCd) {
            lc_repWrkPlCd.setValue(scwin.userInfo.fixWrkPlCd); // 정비작업장코드
        }
    };
};

scwin.udc_eqCd_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNo, ed_eqCd, 1, false)
};

scwin.udc_eqCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_eqCd.getValue(), ed_vehclNo.getValue(), 'F', 'T')
};

scwin.udc_acctDeptCd_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_acctDeptNm, ed_acctDeptCd, 2, false);
};

scwin.udc_acctDeptCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_acctDeptCd.getValue(), ed_acctDeptNm.getValue(), 'F', 'T');
};

scwin.lc_homeClsCd_onviewchange = function (info) {
    var luxIndex = lc_homeClsCd.getValue();
    // 대표정비작업장콤보 조회
    scwin.f_RetrieveSecond(luxIndex);
};

//작업장콤보
scwin.lc_repWrkPlCd_onchange = function (info) {
    // 정비작업장
    if (lc_repWrkPlCd.getValue() == "") return;
    dma_wrkPlCd.set("param2", lc_repWrkPlCd.getValue());

    $c.sbm.execute(sbm_lux_wrkPlCd);
};

scwin.sbm_lux_wrkPlCd_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        lc_wrkPlCd.setSelectedIndex(0);
        if (lc_homeClsCd.getValue() == scwin.userInfo.eqHomeClsCd) {
            lc_wrkPlCd.setValue(scwin.userInfo.fixWrkPlCd); // 정비작업장코드
        }
    }
};

scwin.udc_eqCd_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_eqCd, ed_vehclNo, 1, false);
};

scwin.udc_acctDeptCd_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_acctDeptCd, ed_acctDeptNm, 2, false);
};
